#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=105,M=10005;//记得改数据范围 
const ll inf=1e17;
int n,m,s,t,fir[M],a[N][N];//fir为弧优化数组
int dx[]={0,0,1,-1},dy[]={1,-1,0,0};
struct node
{
	int v,w,fan;//fan记录反向边的位置（g[v][g[u][i].fan]就是g[u][i]的反向边） 
};
ll lev[M];
vector<node> g[N];
void add(int u,int v,int w)
{
	g[u].push_back(node{v,w,g[v].size()});
	g[v].push_back(node{u,0,g[u].size()-1});//反向边只建一个w为0的
}
bool bfs()//顺便看一下图是不是联通的 
{
	for(int i=1;i<=n*m+2;i++)
	{
		lev[i]=inf;
		fir[i]=0;
	}
	queue<int> q;
	q.push(s);
	lev[s]=0;
	while(!q.empty())
	{
		int u=q.front();
		q.pop();
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i].v,w=g[u][i].w;
			if((w>0)&&(lev[v]==inf))
			{
				q.push(v);
				lev[v]=lev[u]+1;
				if(v==t) return 1;
			}
		}
	}
	return 0;
}
ll dfs(int u,ll mn)//mn是目前找到的这条增广路的min 
{
	if(u==t) return mn;
	ll ans=0;
	for(int i=fir[u];i<g[u].size();i++)
	{
		fir[u]=i;
		int v=g[u][i].v,w=g[u][i].w;
		if((w>0)&&(lev[v]==lev[u]+1))
		{
			ll num=dfs(v,min(mn,(ll)w));
			if(num==0) lev[v]=inf;
			g[u][i].w-=num;
			g[v][g[u][i].fan].w+=num;//反向边
			ans+=num;
			mn-=num;
		}
	}
	return ans;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	s=n*m+1;
	t=s+1;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			cin>>a[i][j];
		}
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			if(a[i][j]==1)
			{
				add(s,(i-1)*m+j,inf);
			}
			else if(a[i][j]==2)
			{
				add((i-1)*m+j,t,inf);
			}
		}
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			for(int k=0;k<4;k++)
			{
				int nx=i+dx[k],ny=j+dy[k];
				if((nx<=n)&&(ny<=m)&&(nx>=1)&&(ny>=1))
				{
					add((i-1)*m+j,(nx-1)*m+ny,1);
				}
			}
		}
	}
	ll ans=0;
	while(bfs())
	{
		ans+=dfs(s,inf);
	}
	cout<<ans;
	return 0;
}
